INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027da1e3c98b0941765b56', '前台姑娘态度还是不错的，送了入住鲜花。酒店地处广州旧cbd黄金地段，交通便利。酒店富丽堂皇，外国人云集，但因为设计年代久远，尽显年代气息，花园酒店，广州必定要打卡的地标建筑之一', '["https://dimg04.c-ctrip.com/images/0231z12000ciym1es2324_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000ciyiyum354A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000ciyek35DAC9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-06', '红棉双床套房', '套房', '朋友出游', 88, 0, 4, 7, '["前台服务","交通便利性","整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度'),
('68027da1e3c98b0941765b57', '这次和家人来到广州游玩，入住了越秀区的广州花园酒店。团的是之前在携程订的套餐服务，有幸升级了套房。性价比上没得说，1600住了两晚。还有行政。李玉旋转餐厅的早餐。但是套房的缺点就是设施成就领域期的水忽冷忽热。正值楼下地铁施工，每天早上8点都会有。机器的声音伴随着闹钟声响虽然出门旅游不会睡懒觉，但是这个还是有一点美中不足。作为老牌酒店，他们的服务还是非常的不错，特别是在广交会期间。外国人虽然繁多，但是服务总体还是非常的热情，能够感受到五星级酒店的特殊。', '["https://dimg04.c-ctrip.com/images/0236912000cfpq051A9A1_R_150_150_R5_Q70_D.webp","https://dimg04.c-ctrip.com/images/0232212000cfppthe1BDB_R_150_150_R5_Q70_D.webp","https://dimg04.c-ctrip.com/images/0232c12000cfpomvyB81C_R_150_150_R5_Q70_D.webp"]'::jsonb, 4.7, 4, '2023-10-22', '花园大床房', '大床房', '朋友出游', 227, 0, 15, 8, '["性价比","房间设施","安静程度"]'::jsonb, '性价比', '房间设施', '安静程度'),
('68027da1e3c98b0941765b58', '酒店就是住在花园里，亮点是花园瀑布下午茶，还有4楼博物馆也可免费参观，很不错的体验哦', '["https://dimg04.c-ctrip.com/images/0235o12000cylf1nf3A67_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000cylwem06FA9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n12000cyl2iyp8E71_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000cylw82h7600_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-17', '花园大床房', '大床房', '家庭亲子', 42, 0, 13, 7, '["公共设施","整体满意度"]'::jsonb, '公共设施', '整体满意度', NULL),
('68027da1e3c98b0941765b59', '房间温馨，床品很好，服务范到位。餐厅美食完美多样！可以停车后不能直达大厅，需要出地面步行一小段才可以。', '["https://dimg04.c-ctrip.com/images/0234h12000cwm3gjs0027_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000cwly5rr2CF0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000cwlqwzf0862_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000cwlgp2x01D7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-10', '城央绿意大床房', '大床房', '情侣出游', 51, 0, 28, 6, '["房间设施","餐饮设施","公共设施"]'::jsonb, '房间设施', '餐饮设施', '公共设施'),
('68027da1e3c98b0941765b5a', '值得信赖携程推荐，短短的三天让我们体会到了广州花园酒店服务管理水平和世界名牌酒店的接轨，选择花园酒店是我们的首选??????', '["https://dimg04.c-ctrip.com/images/0205p12000cr5hlrgF3B1_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0234h12000cr5d7iu3635_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-18', '花园双床房', '双床房', '其他', 62, 0, 14, 5, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027da1e3c98b0941765b5b', '酒店过年气氛很好，酒店环境不错，有瀑布花园，适合全家出游', '["https://dimg04.c-ctrip.com/images/0236n12000d77r60j954F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-02-14', '花园双床房', '双床房', '家庭亲子', 28, 0, 34, 5, '["周边配套","整体满意度"]'::jsonb, '周边配套', '整体满意度', NULL),
('68027dabe3c98b0941765b5c', '大堂布置精美，后花园景色很美，房间卫生不错，工作人员服务热情。入住率高，早餐需排队等候。
酒店旁边有施工，略吵
康体中心洗浴设施旧，热水供应不足', '["https://dimg04.c-ctrip.com/images/0236112000cn1vlfb304A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000cn20eyz52DD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000cn22x7s6357_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-11-26', '红棉大床套房', '套房', '家庭亲子', 72, 0, 19, 7, '["安静程度","房间设施","公共设施"]'::jsonb, '安静程度', '房间设施', '公共设施'),
('68027dabe3c98b0941765b5d', '广州的老牌五星酒店，服务还是不错的，环境也很好，酒店干净卫生，就是我们入住的房间位置很偏感觉不是很舒服。', '["https://dimg04.c-ctrip.com/images/0232612000ddf56nn98D4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000ddf5z0720AF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000ddf5atnAB50_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-03-08', '花园双床房', '双床房', '朋友出游', 52, 0, 33, 6, '["整体满意度","卫生状况","景观/朝向"]'::jsonb, '整体满意度', '卫生状况', '景观/朝向'),
('68027dabe3c98b0941765b5e', '感受下老酒店历久弥新～属实是不错的，整体的感觉，除了客房层高偏矮，老酒店也确实是如此，现在也足可见当年的辉煌', '["https://dimg04.c-ctrip.com/images/0236u12000csht5woB3B8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000cshv53w96C2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000cshrxrzD505_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000cshtfct038A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000cshxu073F68_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000cshy634D446_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000cshsv4346A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000cshxt3uC42C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000csi02ctDCAB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-24', '花园大床房', '大床房', '独自旅行', 54, 1, 56, 6, '["整体满意度","房间设施"]'::jsonb, '整体满意度', '房间设施', NULL),
('68027dabe3c98b0941765b5f', '酒店地理位置非常好，环境优美，国庆节活动丰富多彩。酒店本身很有历史文化底蕴，建议可以体验酒店介绍的26个打卡点，特别感谢小梁的细致周到讲解，下次还会选择这里。', '["https://dimg04.c-ctrip.com/images/0236g12000fxdd08g042E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000fxe89vc52A6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000fxauz2d8C46_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-02', '花园双床房', '双床房', '家庭亲子', 79, 0, 4, 8, '["整体满意度","周边配套","前台服务"]'::jsonb, '整体满意度', '周边配套', '前台服务'),
('68027dabe3c98b0941765b60', '这次选择了历史悠久的花园酒店 
1k+的2天1夜大床套餐真的很划算（含早+晚，叠叠高一份）check in的时候前台小姐姐还给宝宝送了冰箱贴 她好开心
??
本来我们套餐是花园大床 考虑到我们有宝宝 给我们升级到了红棉套房 比原来房间面积大了一倍 感谢酒店的贴心安排
房间里的缺点就是 老旧的味道有点点重 空调也是时不时会有很强的运转声音 其他都还阔以
枕头如果睡得不合适可以让服务员换的
??
选择这个酒店就是他们家好吃的特别多 荔湾亭和瀑布酒店我们都试了 真的不错 瀑布餐厅的自助晚餐我个人认为与其他酒店的自助晚餐都不太一样 菜式都比较有新意 味道也很不错 最近活动价388/位 推荐来试试 
荔湾亭的1蚊1碗豆腐花活动也是很惊艳 整体出品也在线 推荐
??
在花园酒店里面逛一天没有问题 还有博物馆可以参观（周一休馆）免费开放的
服务是不错的 工作人员都会耐心细致地回答我们提出的疑问', '["https://dimg04.c-ctrip.com/images/0232712000c8ygeki60A2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000c8ycfubF6BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000c8y9vnw4FB4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000c8yhwi8C41E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000c8yeofl7B81_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000c8y55gqA746_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000c8ybox7243C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235y12000c8yfk6e17DF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000c8ya08v6A94_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-09-26', '花园大床房', '大床房', '家庭亲子', 395, 0, 11, 9, '["性价比","餐饮设施","前台服务"]'::jsonb, '性价比', '餐饮设施', '前台服务'),
('68027dabe3c98b0941765b61', '酒店在老城区，外宾比较多。花园房型设施比较老旧，套房是新装修还可以。', '["https://dimg04.c-ctrip.com/images/0233p12000d6qc49e15DF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-02-12', '花园双床房', '双床房', '家庭亲子', 34, 0, 24, 6, '["房间设施"]'::jsonb, '房间设施', NULL, NULL),
('68027dabe3c98b0941765b62', '房间忘记拍摄了，非常不错床很舒服睡了好觉', '["https://dimg04.c-ctrip.com/images/0234e12000daukljxAA4C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000dauo4oiF4DE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-27', '花园双床房', '双床房', '商务出差', 20, 0, 27, 4, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027dabe3c98b0941765b63', '庆祝结婚纪念日，好多谢花园酒店为我们带来惊喜，不但布置了房间还送了一个漂亮的蛋糕，免费升级了房型，服务和环境非常nice，下次还会继续选择，感谢这次为我们服务的各位靓女们，非常感谢！??????????', '["https://dimg04.c-ctrip.com/images/0232212000ce0aofb268F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231b12000ce0ao2w3E4F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000ce0aknq02FA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000ce0aomz1FCB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000ce0ao475DD7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000ce0aozkD858_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000ce0arpk0EFD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000ce0anqw5E98_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230h12000ce0at3l179C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-14', '红棉大床套房', '套房', '情侣出游', 101, 0, 2, 8, '["前台服务","整体满意度","客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务'),
('68027dabe3c98b0941765b64', '花园作为老五星，不管是服务上还是设施上都应该有它的名字。
先说这次的不足：
①广交会期间，办理入住窗口仅开放两个，导致入住等待将近一个小时期间。办理入住是迎宾的第二道线，如果长时间焦灼等待，让本来就旅途疲惫的人打破第一印象。
②外宾与外地宾客的接待，服务上会有一定差异，可以理解是因为会议期间作为接待酒店，对外宾有相应的服务。但，是不是忽略了一些游客的感受
③临街地铁施工，非常吵。周末无休早8晚10，在办理入住时无人提示，导致好不容易办好入住，又需要调换房间。如实在是没有其他房间调换的宾客，也未提前准备耳塞。

再说下好的地方：
①服务：从迎宾至早上的贴心服务，礼宾部做到应该做的标准五星酒店应有的程度
②环境交通：相对交通便利，如果为了吃饭购物相对方便。
③卫生：卫生还是依旧很干净，部分配置相对老旧，但扛得住用
希望作为老五星，去其糟粕取其精华，越来越好', '["https://dimg04.c-ctrip.com/images/0233g12000ce8w41r8BE4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-15', '花园大床房', '大床房', '独自旅行', 381, 0, 2, 9, '["退房/入住效率","安静程度","整体满意度"]'::jsonb, '退房/入住效率', '安静程度', '整体满意度'),
('68027dabe3c98b0941765b65', '给免费升级了红棉大床房 房间确实很大 还有健身器材 早餐也很丰富 唯一不好的是楼下市政建设在修地铁 好在晚上十点结束 早上八九点才开始施工 酒店本身服务是很好的 地理位置也很优越', '["https://dimg04.c-ctrip.com/images/0232c12000chwnssyCACF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000chwdccv5926_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000chwme6v6440_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000chwa6ooF554_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000chwjxv55BA2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-02', '红棉大床套房', '套房', '家庭亲子', 89, 0, 14, 8, '["整体满意度","房间设施","安静程度"]'::jsonb, '整体满意度', '房间设施', '安静程度'),
('68027db6e3c98b0941765b66', '很喜欢住在花园，酒店很有底蕴，但房间设施又比较新，不管是酒店的味道还是服务都很舒服。入住有送鲜花，真的让人心情很好。
特别喜欢行政酒廊的Beryle，人美声甜，服务真的没话说，身边其他客人也非常喜欢她，整个入住期间的体验因为有她在，更加让人感到舒心。下次还会选择住花园酒店。', '["https://dimg04.c-ctrip.com/images/0230h12000f8h4mp8F1E4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000f8hb1n8CBE2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000f8hc2rv82D5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r12000f8gzhnh0FAC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000f8h1ngrBBAE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-24', '花园大床房', '大床房', '商务出差', 137, 0, 7, 8, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027db6e3c98b0941765b67', '整体设计富丽堂皇！
房间略有烟味！
枕头、床垫非常舒服！
出行方便，近地铁！', '["https://dimg04.c-ctrip.com/images/0231p12000cztdwuw97C7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-21', '花园双床房', '双床房', '家庭亲子', 38, 0, 6, 5, '["房间设施","交通便利性","整体满意度"]'::jsonb, '房间设施', '交通便利性', '整体满意度'),
('68027db6e3c98b0941765b69', '多次入住了，一直都是特别满意，服务、环境、设施都是一流', '["https://dimg04.c-ctrip.com/images/0230s12000d7po1tg4A42_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000d7pwswlEBCA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000d7q8641D4BB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-15', '红棉大床套房', '套房', '家庭亲子', 27, 0, 1, 5, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027db6e3c98b0941765b6a', '看了小红书介绍有点担心。
真正入住后体验不错，房间干净（完全没味道），床品非常舒服。老钱风。
在瀑布下的餐厅吃早饭惬意。
感谢Rachel和Rebeca小姐姐安排。', '["https://dimg04.c-ctrip.com/images/0234o12000ex1irk960AA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-27', '花园双床房', '双床房', '商务出差', 82, 0, 3, 7, '["房间设施","卫生状况","餐饮设施"]'::jsonb, '房间设施', '卫生状况', '餐饮设施'),
('68027db6e3c98b0941765b6b', '服务周到，活动丰富，人性化设计为全家游留下美好回忆。', '["https://dimg04.c-ctrip.com/images/0235m12000d7jlj8gC5AD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000d7j6g2z5425_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000d7jexb92828_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-15', '城央绿意大床房', '大床房', '家庭亲子', 26, 0, 8, 4, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68027db6e3c98b0941765b6c', '房间卫生非常差，楼下工程噪音通宵吵无法入睡，套房也没有准备水果，在哪里住酒店套房都会帮客人提前准备水果。房间地毯脏的惨目不堵。', '["https://dimg04.c-ctrip.com/images/0232h12000couvi3z1834_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.7, 2, '2023-12-06', '红棉大床套房', '套房', '商务出差', 63, 4, 44, 8, '["卫生状况","安静程度","客房服务"]'::jsonb, '卫生状况', '安静程度', '客房服务'),
('68027db6e3c98b0941765b6d', '设施：高端舒适
卫生：干净
环境：优美
服务：服务一流', '["https://dimg04.c-ctrip.com/images/0232o12000d6f9ixp1557_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-11', '花园双床房', '双床房', '家庭亲子', 27, 0, 6, 4, '["整体满意度","卫生状况","房间设施"]'::jsonb, '整体满意度', '卫生状况', '房间设施'),
('68027db6e3c98b0941765b6e', '床好，水好，服务好。早餐丰盛，而且国际化，又有本地特色。十分开心。', '["https://dimg04.c-ctrip.com/images/0231y12000d1q62k47253_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-26', '城央绿意大床房', '大床房', '独自旅行', 33, 0, 3, 5, '["餐饮设施","整体满意度","房间设施"]'::jsonb, '餐饮设施', '整体满意度', '房间设施'),
('68027db6e3c98b0941765b6f', '花园酒店位于市中心交通非常的便利，酒店也非常的豪华花园也十分美丽，工作人员的服务也十分的好，特别是大堂的小何', '["https://dimg04.c-ctrip.com/images/0232c12000jrl88n2B92B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000jrlbbrb7B1B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000jrkqqz42E02_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-13', '花园大床房', '大床房', '情侣出游', 54, 0, 4, 6, '["交通便利性","整体满意度","前台服务"]'::jsonb, '交通便利性', '整体满意度', '前台服务'),
('68027dc3e3c98b0941765b70', '花园酒店的大堂很有特色，非常大气，酒店交通非常方便，地铁站就在酒店旁边，服务也很贴心。', '["https://dimg04.c-ctrip.com/images/0234012000cxdel22D99A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-01-13', '花园双床房', '双床房', '家庭亲子', 43, 0, 6, 6, '["交通便利性","前台服务","公共设施"]'::jsonb, '交通便利性', '前台服务', '公共设施'),
('68027dc3e3c98b0941765b71', '每次到广州，心心念念就是花园酒店，第一批白金五星称号，全中国没几家，斥巨资、重服务，一进酒店大堂就能感受到富丽堂皇，金碧辉煌。一整面墙的红楼梦，古典、大气。
入住的时候，超级nice，因为带了小朋友，小朋友早班飞机很累，想提早入住，给了我们一间不错的房间，送了月饼送了早餐券送了很多欧舒丹洗漱用品，还有小玩具，也是这里有售卖的。
然后服务超级棒。
南航旗下，也会看到其他航空公司工作人员入住。', '["https://dimg04.c-ctrip.com/images/0234i12000cud57bi6563_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q12000cud4oviF38B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230l12000cud3fw14F59_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232v12000cucyv1a9880_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000cud562l4EBF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235212000cud562nEEC7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000cud3il498D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000cud087o4568_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000cud45573D0D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-01', '红棉双床套房', '套房', '家庭亲子', 196, 0, 2, 9, '["前台服务","整体满意度","客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务'),
('68027dc3e3c98b0941765b72', '有多少人跟我一样认为，里面的人员和服务员多么崇洋媚外？', '["https://dimg04.c-ctrip.com/images/0231l12000d8t3p02B8F2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-02-19', '花园双床房', '双床房', '朋友出游', 27, 0, 8, 2, '["前台服务"]'::jsonb, '前台服务', NULL, NULL),
('68027dc3e3c98b0941765b73', '酒店非常的不错，酒店大堂很豪华，服务也很不错，特别是大堂的whaley服务不错', '["https://dimg04.c-ctrip.com/images/0232g12000ewz58g2BAAA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000ewz7mgdDBB6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000ewz9f7i5C02_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000ewyy6ho2B45_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000ewz0cafD739_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235d12000ewzazyx7FB2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000ewz1jqh1F73_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233112000ewz7f4oBFE7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r12000ewyvnrjA676_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-27', '花园大床房', '大床房', '朋友出游', 39, 0, 2, 6, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027dc3e3c98b0941765b74', '带宝宝出行  酒店房间中规中矩  就是隔音太差  旁边房间的关门声 都听的一清二楚而且声音不小  
酒店大堂很气派  也有自己的博物馆  花园可以逛逛  
早餐  一般般  不符合这个五星级酒店的标准  
交通  步行一分钟到达??淘金站  过条马路直达小蛮腰  其他景区换乘??  或者门口有车大概都是20分钟之内 
总体酒店中规中矩  没有大问题', '["https://dimg04.c-ctrip.com/images/0233r12000cdjm7btB4B6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000cdjooz8DDDC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000cdjogxv4576_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000cdjjz1r0654_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000cdjksdxD7EA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-12', '花园双床房', '双床房', '家庭亲子', 175, 0, 19, 7, '["安静程度","交通便利性","餐饮设施"]'::jsonb, '安静程度', '交通便利性', '餐饮设施'),
('68027dc3e3c98b0941765b75', '酒店服务态度很好，一来到酒店，就会有服务员咨询办理什么、教你去哪里办理或者寄托行李，酒店环境不错，不过我没住到免费升级房间，不过最起码没住正在施工的那边房间已经很好了??，不过隔音一般，会听到响声，而且厕所细，只有浴缸没浴室', '["https://dimg04.c-ctrip.com/images/0236f12000cb4lj6x862B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000cb4pw1gC68D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p12000cb4ow5xA037_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230112000cb4sy1m09CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000cb4mbt6BC6D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000cb4mdc48785_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000cb4q980209D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b12000cb4ovftC8F4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000cb4o08yAFEA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-02', '花园双床房', '双床房', '家庭亲子', 112, 0, 8, 7, '["前台服务","安静程度","房间设施"]'::jsonb, '前台服务', '安静程度', '房间设施'),
('68027dc3e3c98b0941765b76', '老牌五星酒店，服务品质很好，自助餐食也不错', '["https://dimg04.c-ctrip.com/images/0230t12000d8sk8ni3AAF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000d8s5h3h0546_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000d8sei603D5D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-19', '花园大床房', '大床房', '朋友出游', 21, 0, 107, 5, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68027dc3e3c98b0941765b77', '感谢为我们升了房型，酒店非常漂亮，富丽堂皇的大堂，瀑布餐厅的景观，小桥流水，锦鲤，亭台楼阁都出乎意料；
套餐的行政礼遇让我们基本就在酒店解决，酒廊的Winnie Carrie 一直为我们忙前忙后，冷气太足还为我妈妈送上了毯子；
花园酒店是整个广东行程中住得最满意的，下次有机会再来入住。', '["https://dimg04.c-ctrip.com/images/0235t12000cnxs8iaD9C7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231i12000cnxnsm6AA34_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000cnxoz4eBA1B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000cnxr6xjD8DA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000cnxqgliCFB0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-01', '花园双床房', '双床房', '家庭亲子', 143, 0, 2, 8, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027dc3e3c98b0941765b78', '房间很大，新装修的，很干净，服务也不错，本来订了红棉双床房，想换大床，前台小姐姐说大床房有点吵，直接给升级了，就是灯光还是传统老牌酒店的效果比较暗，如果有个白灯感觉更舒服一点，早餐餐厅的环境不错，选择不多，不过味道还挺好', '["https://dimg04.c-ctrip.com/images/0236p12000ccu5ch82E05_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000ccu6l8c46CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231i12000ccu747oCA44_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000ccu6cdo9A4D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-08', '红棉双床套房', '套房', '家庭亲子', 110, 0, 4, 8, '["房间设施","前台服务","餐饮设施"]'::jsonb, '房间设施', '前台服务', '餐饮设施'),
('68027dc3e3c98b0941765b79', '给男朋友庆生，check in的时候前台给升级了套房，并且客房在房间布置有一些花瓣和祝福，这让男朋友感到很惊喜和满意。晚餐是在瀑布餐厅吃的，环境OK，服务很好，服务员还端上生日蛋糕来给男朋友唱生日歌，美中不足的是自助餐的海鲜种类不是很丰富，晚上看瀑布的景不是很清晰', '["https://dimg04.c-ctrip.com/images/0234x2224wpiwfr4h8B1F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023472234csw2ixps4127_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234e2224wpiwge9uAD2F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h2215gm5qe2jk7B32_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-08', '花园大床房', '大床房', '情侣出游', 132, 0, 2, 8, '["前台服务","客房服务","餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施'),
('68027dcde3c98b0941765b7a', '国庆广州行，选择了花园酒店入住，酒店历史悠久，很有广州特色，每一位工作人员服务都非常好，入住1849房间，房间空间不大，床很舒适，客房服务也很细致入微。酒店处处是景，酒店里博物馆非常值得去看看，双瀑布花园很惊艳，很喜欢这里，酒店38周年了，服务绝对还是行业首屈一指??，来过你就能体会到，什么是用心的服务??有机会还会再来。', '["https://dimg04.c-ctrip.com/images/0231512000cbj7s298309_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000cbj7s2c17D9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000cbj56hkE144_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000cbj5swb1CF1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000cbj6n5uA2B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000cbj55rw974F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000cbj6ni98565_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000cbj3tzaAD52_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000cbj6p1fB9A3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-03', '花园大床房', '大床房', '情侣出游', 162, 0, 20, 9, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68027dcde3c98b0941765b7b', '房间干净，床品舒服。大堂富丽豪华，电梯多。花园人工瀑布正对餐厅，别据一格。
出门就是地铁口，走那儿都方便。
旁边几百米陶陶居，再往前白云山公园。都很方便。
缺点：前台旁摆放巴宝丽洗漱用品，但房间内不是。', '["https://dimg04.c-ctrip.com/images/0231212000ccr1lxl58F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000ccr11hz4BC3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000ccqxim2E0BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000ccr1e04988B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-08', '花园大床房', '大床房', '商务出差', 101, 0, 7, 7, '["房间设施","周边配套","交通便利性"]'::jsonb, '房间设施', '周边配套', '交通便利性'),
('68027dcde3c98b0941765b7c', '酒店非常便捷，房间很舒适，服务水准高，十分推荐', '["https://dimg04.c-ctrip.com/images/0236712000d7pjdy41860_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-15', '红棉大床套房', '套房', '家庭亲子', 23, 0, 1, 4, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('68027dcde3c98b0941765b7d', '设施:免费升级为粤韵双床房
服务：挺好，就是前台和客服对早茶的情况不了解，也不清楚能不能提前预约，白天鹅那边就做的很好，这方面花园酒店有待改进

环境：很好，有前后花园，特别后花园有瀑布，在市区很少有这么大面积的酒店花园', '["https://dimg04.c-ctrip.com/images/0232212000ccg179zD9BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000ccg1mpd1F15_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000ccg1rb8399E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000ccg28fk6224_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p12000ccfzssaB970_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-07', '花园双床房', '双床房', '家庭亲子', 110, 0, 2, 7, '["公共设施","前台服务","整体满意度"]'::jsonb, '公共设施', '前台服务', '整体满意度'),
('68027dcde3c98b0941765b7e', '酒店繁华朵朵！前台小哥态度诚恳、美女温柔体贴给康乃馨花束！瀑布餐厅的服务员们敬业、菜品味道不错！30楼行政廊眼镜美女小周善解人意、可爱体贴！客房服务大姐到位！花园酒店的二天舒心安逸！', '["https://dimg04.c-ctrip.com/images/0234w12000cyxsayb4777_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233k12000cyxia0f6B4E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000cyxo8z5812A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000cyxru5x38E1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000cyxx0uq8E65_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000cyxvmos5FDD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000cyxu7kgEBD6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-18', '花园大床房', '大床房', '情侣出游', 91, 1, 60, 7, '["前台服务","餐饮设施","客房服务"]'::jsonb, '前台服务', '餐饮设施', '客房服务'),
('68027dcde3c98b0941765b7f', '酒店比较旧，设施都有些旧，热水水温不太稳定，下水也不利索了。
但是但是但是……非常喜欢这种有历史感酒店，老派豪华酒店代表了一个城市的兴衰史。服务上感觉到浓厚的酒店文化，前台服务生给人感觉非常舒服，硬生生靠服务和充满时代感的设计赢得了我的喜爱。酒店里的早茶、博物馆、内部花园是亮点。', '["https://dimg04.c-ctrip.com/images/0233d12000ccde6asCC45_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000ccdfvpp85C0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000ccdgpqfA2A7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-06', '花园大床房', '大床房', '其他', 140, 0, 34, 9, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('68027dcde3c98b0941765b80', '这次在花园酒店的入住体验堪称完美！从踏入大堂的那一刻起，就被优雅的壁画景观和温馨的氛围所吸引。花园大使Anna热情主动，服务细致入微，礼宾Wayne提前联系询问需求，专业周到，还有非常可爱的前台小姐姐小鱼小谢~而且房间视野超赞！房内设施现代齐全，床品柔软舒适。早餐种类丰富，蛋糕点心和现磨咖啡都很精致。退房时还收到了小礼物，全程体验无可挑剔，下次来city必须二刷！', '["https://dimg04.c-ctrip.com/images/0236012000jir3jwzD270_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b12000jiswbwx2EE3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000jir37aeC721_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-03', '红棉大床套房', '套房', '情侣出游', 183, 0, 14, 9, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027dcde3c98b0941765b81', '这是第二次入住花园酒店，回想第一次入住是2016年的冬天，距离这次已经7年时间了，但是花园酒店给我的感觉还是非常大的惊喜。从进入酒店开始就有很多小姐姐微笑的询问需要什么帮助，前台给了20楼的房间，视野很开阔，我还买了酒店的礼品小羊羊。第二天起床品尝了二楼的米其林餐厅荔湾亭，坐到了花船，环境食物茶水都好评。三楼餐厅没有来得及去品尝，下次再有机会吧。酒店里有20多处打卡打卡点，我们几乎都去了，后花园的瀑布和锦鲤真的很美，孩子看到鱼非常高兴，在花园里转了好几圈。房间设施齐全，虽然酒店年代已久，但是住着仍然很舒适，周边车站地铁和商场饭店都很齐全。酒店门口打车真的太方便了。这次看到奠基是1980年….居然和我同岁，哈哈??，下次来广州还是会入住花园酒店！', '["https://dimg04.c-ctrip.com/images/0231c12000cdgm5cl5124_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000cdgrdis4F59_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000cdgmfeq58C9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000cdgjq7615D6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234x12000cdgr5afC155_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000cdgmv9j1EB9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000cdgm5cnFADD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000cdgpa9eAD5C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-11', '花园双床房', '双床房', '家庭亲子', 326, 0, 60, 9, '["整体满意度","周边配套","前台服务"]'::jsonb, '整体满意度', '周边配套', '前台服务'),
('68027dcde3c98b0941765b82', '粤韵房非常不错，白天下面在修路是有点声音，在客厅能听到一点，但是房间基本听不到

设施：相对旧一点，属于有点年代的味道
卫生：可以
环境：酒店装修有种穿越的感觉，装修非常的气质奢华，老钱风。非常不错（瀑布，小桥，肥嘟嘟的锦鲤）
服务：反应挺快，毕竟是白金，这方面可以的

酒店内有个博物馆（星空墙）可以去看看，拍拍照', '["https://dimg04.c-ctrip.com/images/0236x12000cc9jovv95F3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000cc9if77E4E3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000cc9mux69457_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-06', '城央绿意大床房', '大床房', '朋友出游', 158, 0, 1, 8, '["安静程度","整体满意度","房间设施"]'::jsonb, '安静程度', '整体满意度', '房间设施'),
('68027dcde3c98b0941765b83', '房间蛮新的，重新装修，不是想象中很老的破五星，大堂特别气派，关键酒店里吃货的天堂，二楼荔湾亭早茶及中晚餐味道很好，三楼桃园馆是米其林餐厅，做的色香味俱全，很细腻，味道很好！一定要品尝，吃了对面广州酒家后觉得还是酒店里好吃！', '["https://dimg04.c-ctrip.com/images/0236i12000cc59cwlE010_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r12000cc5dnn12237_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000cc5g6ylAC42_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000cc5ezc620F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000cc5d4qf452F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000cc5b0wlD11B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000cc5cg9v93C2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-05', '花园双床房', '双床房', '家庭亲子', 111, 0, 44, 9, '["餐饮设施","房间设施","整体满意度"]'::jsonb, '餐饮设施', '房间设施', '整体满意度'),
('68027dd8e3c98b0941765b84', '房间住得舒适，卫生干净，整洁，在房间还可以看到瀑布，我们订了三间房间还送了欢迎水果，酒店每位服务人员服很好，特别前台帮我们办理入住的小帅哥，阿根廷人，讲普通话棒棒的，我们还免费享受了金牌讲解介绍酒店，参观酒店所有景点，历史，在酒店2楼餐厅吃得很好，出品很有特色', '["https://dimg04.c-ctrip.com/images/0233512000cv6dl1335B8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000cv6oz7cE9E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000cv6mwxoECFB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000cv6dihk74BB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230h12000cv6g7yw1005_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000cv6pexgE226_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000cv6mu2u09CA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-04', '红棉大床套房', '套房', '朋友出游', 130, 0, 13, 9, '["整体满意度","前台服务","景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向'),
('68027dd8e3c98b0941765b85', '春节入住，节日氛围浓厚，醒狮很精彩，服务很周到', '["https://dimg04.c-ctrip.com/images/0230k12000d6hwrg6D4B5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-11', '花园大床房', '大床房', '家庭亲子', 23, 0, 1, 5, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027dd8e3c98b0941765b86', '作为每次去广州首选的酒店，喜欢的是它的沉淀，住在这里有踏实感', '["https://dimg04.c-ctrip.com/images/0231112000d1pzb8zD813_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000d1qc5iq7299_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-26', '花园大床房', '大床房', '商务出差', 30, 0, 5, 5, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027dd8e3c98b0941765b87', '前厅部管理非常完美 系广州地区见过最有管理、最有笑容、服务最主动积极的前厅部
特别好的感觉是去到大堂，姐姐看到孩子主动送上当天酒店烤好的曲奇饼，自助餐虽然不是见过品种最多的，但每一样都是很精，客房服务也是非常好的感受，孩子说我们还要再来！', '["https://dimg04.c-ctrip.com/images/0234n12000c25biqfA46C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000c25ch0nB911_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000c25am0c2E0D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236312000c25cs14E8E2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235012000c25afg56DE7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000c25iymq75EA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n12000c256a2z4968_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231e12000c25cm8r5C74_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000c25gmz2C235_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-03', '红棉大床套房', '套房', '家庭亲子', 119, 3, 7, 9, '["前台服务","餐饮设施","客房服务"]'::jsonb, '前台服务', '餐饮设施', '客房服务'),
('68027dd8e3c98b0941765b88', '酒店是广州老牌星级，进门的一瞬间被大堂的装修风格吸睛，服务总体不错，30号住了一晚套间，3号住了两个标间，只是一个房间出得太晚,5点才有，略有些小瑕疵
瀑布餐厅美美哒，照片拍不出现场感受，值得继续刷的酒店', '["https://dimg04.c-ctrip.com/images/0233612000cc97eqa62A0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236u12000cc98r40AC2E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000cc9c62628E5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000cc9c9y4B748_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-10-06', '花园大床房', '大床房', '家庭亲子', 102, 0, 12, 7, '["整体满意度","餐饮设施","退房/入住效率"]'::jsonb, '整体满意度', '餐饮设施', '退房/入住效率')
 ON CONFLICT (_id) DO NOTHING;
